{"file_path": "/tmp/isolated_workspace_1091/query1.html", "content": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>GARGANTUA - Black Hole Visualization</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { overflow: hidden; background: #000; font-family: 'Segoe UI', Arial, sans-serif; }
  canvas { display: block; }

  /* Frosted glass card */
  .info-card {
    position: fixed;
    bottom: 30px;
    left: 30px;
    background: rgba(10, 10, 30, 0.45);
    backdrop-filter: blur(18px);
    -webkit-backdrop-filter: blur(18px);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 16px;
    padding: 24px 28px;
    color: #ccc;
    z-index: 100;
    min-width: 240px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5);
  }
  .info-card h1 {
    font-size: 28px;
    font-weight: 700;
    letter-spacing: 8px;
    margin-bottom: 14px;
    background: linear-gradient(135deg, #a0d2ff 0%, #ffffff 40%, #ffd080 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .info-card .controls-info {
    font-size: 13px;
    line-height: 1.8;
    color: rgba(200, 210, 230, 0.8);
  }
  .info-card .controls-info span {
    color: rgba(160, 210, 255, 0.95);
    font-weight: 600;
  }

  /* Toggle switch */
  .toggle-row {
    display: flex;
    align-items: center;
    margin-top: 16px;
    gap: 10px;
  }
  .toggle-label {
    font-size: 13px;
    color: rgba(200, 210, 230, 0.8);
  }
  .switch {
    position: relative;
    display: inline-block;
    width: 44px;
    height: 24px;
  }
  /* The actual checkbox - accessible but visually minimal */
  .switch input#anim-toggle {
    position: absolute;
    width: 44px;
    height: 24px;
    opacity: 0.01;
    cursor: pointer;
    z-index: 2;
    top: 0;
    left: 0;
    margin: 0;
  }
  .slider {
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(60, 60, 80, 0.6);
    border-radius: 12px;
    transition: 0.3s;
    pointer-events: none;
  }
  .slider:before {
    content: "";
    position: absolute;
    height: 18px;
    width: 18px;
    left: 3px;
    bottom: 3px;
    background: #8ab4f8;
    border-radius: 50%;
    transition: 0.3s;
  }
  .switch input:checked + .slider {
    background: rgba(100, 160, 255, 0.35);
  }
  .switch input:checked + .slider:before {
    transform: translateX(20px);
    background: #60b0ff;
    box-shadow: 0 0 8px rgba(96, 176, 255, 0.6);
  }
</style>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/"
  }
}
</script>
</head>
<body>

<!-- UI Card -->
<div class="info-card">
  <h1>GARGANTUA</h1>
