// ============================================================
// KEY VISUAL PARAMETERS - adjust these to tweak the look
// ============================================================
const BH_RADIUS = 1.0;        // Black hole event horizon radius
const DISK_INNER = 3.0;       // Accretion disk inner edge
const DISK_OUTER = 10.0;      // Accretion disk outer edge
const GRAV_CONSTANT = 1.5;    // Gravitational bending strength
const EXPOSURE = 1.6;         // Tone mapping exposure (1.0 - 2.0)
const MAX_STEPS = 200;        // Ray marching max steps
const STAR_DENSITY = 0.42;    // Background star density (0.0 - 1.0)
const DOPPLER_STRENGTH = 0.55;// Doppler brightness asymmetry strength

// ============================================================
// VERTEX SHADER - Full screen quad in NDC
// ============================================================
const vertexShader = `
precision highp float;

varying vec2 vUv;

void main() {
  vUv = uv;
  gl_Position = vec4(position, 1.0);
}
`;

// ============================================================
// FRAGMENT SHADER - Black hole ray marching
// ============================================================
const fragmentShader = `
precision highp float;

#define MAX_STEPS 200
#define PI 3.14159265359

// Uniforms updated every frame
uniform float iTime;
uniform vec2 iResolution;
uniform vec3 iCameraPos;
uniform vec3 iCameraDir;
uniform vec3 iCameraUp;
uniform float iFov;

// Physical parameters
uniform float uBhRadius;
uniform float uDiskInner;
uniform float uDiskOuter;
uniform float uGravK;
uniform float uExposure;
uniform float uStarDensity;
uniform float uDopplerStrength;

varying vec2 vUv;

// ---- Hash / noise functions for procedural starfield ----
float hash(vec2 p) {
  p = fract(p * vec2(443.8975, 397.2973));
  p += dot(p, p.yx + 19.19);
  return fract(p.x * p.y);
}

float hash3(vec3 p) {
  p = fract(p * vec3(443.897, 441.423, 437.195));
  p += dot(p, p.yzx + 19.19);
  return fract((p.x + p.y) * p.z);
}

// Simple 3D noise
float noise3D(vec3 p) {
  vec3 i = floor(p);
  vec3 f = fract(p);
  f = f * f * (3.0 - 2.0 * f);
  return mix(
    mix(mix(hash3(i), hash3(i + vec3(1,0,0)), f.x),
        mix(hash3(i + vec3(0,1,0)), hash3(i + vec3(1,1,0)), f.x), f.y),
    mix(mix(hash3(i + vec3(0,0,1)), hash3(i + vec3(1,0,1)), f.x),
        mix(hash3(i + vec3(0,1,1)), hash3(i + vec3(1,1,1)), f.x), f.y),
    f.z
  );
