// ---- Procedural starfield with colored stars ----
vec3 starfield(vec3 dir, float time) {
  vec3 color = vec3(0.0);

  // Normalize direction for spherical lookup
  vec3 d = normalize(dir);

  // Multiple layers of stars at different scales
  for (int layer = 0; layer < 3; layer++) {
    float scale = 80.0 + float(layer) * 120.0;
    vec3 gridPos = d * scale;
    vec3 cell = floor(gridPos);
    vec3 cellFrac = fract(gridPos);

    // Check neighboring cells
    for (int dx = -1; dx <= 1; dx++) {
      for (int dy = -1; dy <= 1; dy++) {
        for (int dz = -1; dz <= 1; dz++) {
          vec3 neighbor = cell + vec3(float(dx), float(dy), float(dz));
          float h = hash3(neighbor + float(layer) * 100.0);

          // Star probability based on density
          if (h > uStarDensity) continue;

          // Star position within cell
          vec3 starPos = neighbor + vec3(
            hash3(neighbor + 0.1),
            hash3(neighbor + 0.2),
            hash3(neighbor + 0.3)
