  uv.x *= aspect;

  vec3 camDir = normalize(iCameraDir);
  vec3 camRight = normalize(cross(camDir, iCameraUp));
  vec3 camUp = cross(camRight, camDir);

  float fovRad = iFov * PI / 180.0;
  float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);

  vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
  vec3 rayOrigin = iCameraPos;

  // Ray marching state
  vec3 pos = rayOrigin;
  vec3 dir = rayDir;
  vec3 colorAccum = vec3(0.0);
  float glowAccum = 0.0;
  vec3 glowColor = vec3(0.0);
  bool absorbed = false;
  bool hitDisk = false;

  float prevY = pos.y;

  for (int i = 0; i < MAX_STEPS; i++) {
    vec3 toCenter = -pos;  // Vector from pos to black hole center at origin
    float r = length(pos);

    // Absorbed by event horizon
    if (r < uBhRadius) {
      absorbed = true;
      break;
    }

    // Escaped to far field
    if (r > 80.0) {
      break;
    }

    // Adaptive step size: smaller near disk, larger far away
    float stepLen;
    if (r < uDiskOuter + 3.0 && r > uDiskInner - 2.0) {
      stepLen = max(0.05, r * 0.02);  // Small steps in disk region
    } else if (r < 3.0) {
      stepLen = 0.04;  // Very small near event horizon
    } else {
      stepLen = max(0.1, r * 0.04);  // Larger steps far away
    }

