  finalColor = finalColor / (1.0 + finalColor);

  // Slight vignette
  vec2 vigUv = vUv * 2.0 - 1.0;
  float vig = 1.0 - 0.3 * dot(vigUv, vigUv);
  finalColor *= vig;

  // Gamma correction
  finalColor = pow(finalColor, vec3(1.0 / 2.2));

  gl_FragColor = vec4(finalColor, 1.0);
}
