  vertexShader: vertexShader,
  fragmentShader: fragmentShader,
  uniforms: {
    iTime:          { value: 0.0 },
    iResolution:    { value: new THREE.Vector2(Math.max(window.innerWidth, 1), Math.max(window.innerHeight, 1)) },
    iCameraPos:     { value: new THREE.Vector3() },
    iCameraDir:     { value: new THREE.Vector3() },
    iCameraUp:      { value: new THREE.Vector3(0, 1, 0) },
    iFov:           { value: 60.0 },
    uBhRadius:      { value: BH_RADIUS },
    uDiskInner:     { value: DISK_INNER },
    uDiskOuter:     { value: DISK_OUTER },
    uGravK:         { value: GRAV_CONSTANT },
    uExposure:      { value: EXPOSURE },
    uStarDensity:   { value: STAR_DENSITY },
    uDopplerStrength: { value: DOPPLER_STRENGTH }
  },
  depthWrite: false,
  depthTest: false
