// Full-screen quad: PlaneGeometry(2,2) in NDC
const quadGeometry = new THREE.PlaneGeometry(2, 2);
const fullScreenMesh = new THREE.Mesh(quadGeometry, blackHoleMaterial);
fullScreenMesh.frustumCulled = false;  // REQUIRED: prevent frustum culling
scene.add(fullScreenMesh);             // Add to scene, NOT to camera

// ============================================================
// ANIMATION LOOP
// ============================================================
const clock = new THREE.Clock();
let shaderTime = 0.0;
const tempVec = new THREE.Vector3();
const resVec = new THREE.Vector2();

function animate() {
  requestAnimationFrame(animate);

  // 1. Update time based on animation toggle
  const animToggle = document.getElementById('anim-toggle');
  const delta = clock.getDelta();
  if (animToggle && animToggle.checked) {
    shaderTime += delta;
  }
  blackHoleMaterial.uniforms.iTime.value = shaderTime;

  // 2. Update resolution from actual drawing buffer (prevents 0,0 in headless)
  renderer.getDrawingBufferSize(resVec);
  blackHoleMaterial.uniforms.iResolution.value.set(
    Math.max(resVec.x, 1),
    Math.max(resVec.y, 1)
  );

  // 3. Update camera uniforms
  blackHoleMaterial.uniforms.iCameraPos.value.copy(camera.position);

  camera.getWorldDirection(tempVec);
  blackHoleMaterial.uniforms.iCameraDir.value.copy(tempVec);

  blackHoleMaterial.uniforms.iCameraUp.value.copy(camera.up);
  blackHoleMaterial.uniforms.iFov.value = camera.fov;

  // 4. Update controls and render
  controls.update();
  renderer.render(scene, camera);
}

// Handle window resize
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

// Start animation
animate();

