    float scale = 80.0 + float(layer) * 120.0;
    vec3 gridPos = d * scale;
    vec3 cell = floor(gridPos);
    vec3 cellFrac = fract(gridPos);

    // Check neighboring cells
    for (int dx = -1; dx <= 1; dx++) {
      for (int dy = -1; dy <= 1; dy++) {
        for (int dz = -1; dz <= 1; dz++) {
          vec3 neighbor = cell + vec3(float(dx), float(dy), float(dz));
          float h = hash3(neighbor + float(layer) * 100.0);

          // Star probability based on density
          if (h > uStarDensity) continue;

          // Star position within cell
          vec3 starPos = neighbor + vec3(
            hash3(neighbor + 0.1),
            hash3(neighbor + 0.2),
            hash3(neighbor + 0.3)
          );

          // Distance from ray to star
          vec3 diff = gridPos - starPos;
          float dist = length(diff);
          float starSize = 0.05 + 0.08 * hash3(neighbor + 0.5);

          if (dist < starSize) {
            float brightness = (1.0 - dist / starSize);
            brightness = brightness * brightness * brightness;

            // Breathing / twinkling effect
            float twinkleSpeed = 0.5 + 2.0 * hash3(neighbor + 0.7);
            float twinklePhase = hash3(neighbor + 0.9) * 6.28;
            float twinkle = 0.6 + 0.4 * sin(time * twinkleSpeed + twinklePhase);
            brightness *= twinkle;

            // Star color: blue supergiants, white, yellow, red dwarfs
            float colorSeed = hash3(neighbor + 0.4);
            vec3 starColor;
            if (colorSeed < 0.15) {
              // Blue supergiant
              starColor = vec3(0.6, 0.8, 1.0);
            } else if (colorSeed < 0.45) {
              // White/blue-white
              starColor = vec3(0.85, 0.9, 1.0);
            } else if (colorSeed < 0.7) {
              // Yellow/white
              starColor = vec3(1.0, 0.95, 0.8);
            } else if (colorSeed < 0.85) {
              // Orange
              starColor = vec3(1.0, 0.7, 0.4);
            } else {
              // Red dwarf
              starColor = vec3(1.0, 0.4, 0.2);
            }

            color += starColor * brightness * (0.5 + 0.5 * float(layer == 0));
          }
        }
      }
    }
  }

  return color;
}

// ---- Accretion disk temperature/color ----
vec3 diskColor(float r, float angle, float time) {
  // Temperature decreases with radius
  float t = smoothstep(uDiskOuter, uDiskInner, r);

  // Base hot colors (inner=white-blue, outer=orange-red)
  vec3 hotColor = vec3(1.0, 0.95, 0.9);     // Inner: near-white
  vec3 warmColor = vec3(1.0, 0.6, 0.2);      // Mid: orange
  vec3 coolColor = vec3(0.8, 0.25, 0.05);    // Outer: deep red-orange

  vec3 baseColor;
  if (t > 0.5) {
    baseColor = mix(warmColor, hotColor, (t - 0.5) * 2.0);
  } else {
    baseColor = mix(coolColor, warmColor, t * 2.0);
  }

  // Add some turbulence / structure to the disk
  float noiseVal = noise3D(vec3(r * 2.0, angle * 3.0, time * 0.3));
  float ring = sin(r * 8.0 - time * 0.5) * 0.15 + 0.85;
  float turbulence = 0.7 + 0.3 * noiseVal;

  // Brightness falls off with radius
  float radialBrightness = pow(smoothstep(uDiskOuter + 0.5, uDiskInner * 0.8, r), 0.8);

  return baseColor * radialBrightness * ring * turbulence;
}

// ---- Main ray marching ----
void main() {
  // Ray construction from camera parameters (NO inverse matrices)
  vec2 uv = vUv * 2.0 - 1.0;
  float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
  uv.x *= aspect;

  vec3 camDir = normalize(iCameraDir);
  vec3 camRight = normalize(cross(camDir, iCameraUp));
  vec3 camUp = cross(camRight, camDir);

  float fovRad = iFov * PI / 180.0;
  float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);

  vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
  vec3 rayOrigin = iCameraPos;

  // Ray marching state
  vec3 pos = rayOrigin;
  vec3 dir = rayDir;
  vec3 colorAccum = vec3(0.0);
  float glowAccum = 0.0;
  vec3 glowColor = vec3(0.0);
  bool absorbed = false;
  bool hitDisk = false;

  float prevY = pos.y;

  for (int i = 0; i < MAX_STEPS; i++) {
    vec3 toCenter = -pos;  // Vector from pos to black hole center at origin
    float r = length(pos);

    // Absorbed by event horizon
    if (r < uBhRadius) {
      absorbed = true;
      break;
    }

    // Escaped to far field
    if (r > 80.0) {
      break;
    }

    // Adaptive step size: smaller near disk, larger far away
    float stepLen;
    if (r < uDiskOuter + 3.0 && r > uDiskInner - 2.0) {
      stepLen = max(0.05, r * 0.02);  // Small steps in disk region
    } else if (r < 3.0) {
      stepLen = 0.04;  // Very small near event horizon
    } else {
      stepLen = max(0.1, r * 0.04);  // Larger steps far away
    }

    // ---- Explicit ray-plane y=0 intersection (prevents missing disk) ----
    if (!hitDisk && abs(dir.y) > 1e-5) {
      float t_plane = -pos.y / dir.y;
      if (t_plane > 0.0 && t_plane <= stepLen * 1.5) {
        vec3 hitPos = pos + dir * t_plane;
        float hitR = length(hitPos.xz);
        if (hitR >= uDiskInner && hitR <= uDiskOuter) {
          hitDisk = true;

          // Angle in disk plane for Doppler + color
          float angle = atan(hitPos.z, hitPos.x);

          // Doppler effect: material orbits counter-clockwise
          // Tangential velocity direction at hit point
          vec3 tangent = normalize(vec3(-hitPos.z, 0.0, hitPos.x));
          float doppler = 1.0 + uDopplerStrength * dot(normalize(dir), tangent);
          doppler = clamp(doppler, 0.3, 2.0);

          // Disk surface color
          vec3 dColor = diskColor(hitR, angle, iTime);

          // Apply Doppler shift to brightness
          dColor *= doppler * doppler;

          // Opacity based on distance from edges
          float edgeFade = smoothstep(uDiskInner, uDiskInner + 0.5, hitR) *
                          smoothstep(uDiskOuter, uDiskOuter - 1.0, hitR);

          colorAccum += dColor * edgeFade * 2.5;

          // Don't break - ray continues through disk and may hit it again from bending
          hitDisk = false;  // Allow multiple disk crossings from lensing
        }
      }
    }

    // Also check previous step crossing y=0 (sign change)
    float curY = pos.y;
    if (i > 0 && !hitDisk && prevY * curY < 0.0 && abs(curY - prevY) > 1e-6) {
      float frac = prevY / (prevY - curY);
      vec3 crossPos = pos - dir * stepLen * (1.0 - frac);
      float crossR = length(crossPos.xz);
      if (crossR >= uDiskInner && crossR <= uDiskOuter) {
        float angle = atan(crossPos.z, crossPos.x);
        vec3 tangent = normalize(vec3(-crossPos.z, 0.0, crossPos.x));
        float doppler = 1.0 + uDopplerStrength * dot(normalize(dir), tangent);
        doppler = clamp(doppler, 0.3, 2.0);
        vec3 dColor = diskColor(crossR, angle, iTime);
        dColor *= doppler * doppler;
        float edgeFade = smoothstep(uDiskInner, uDiskInner + 0.5, crossR) *
                        smoothstep(uDiskOuter, uDiskOuter - 1.0, crossR);
        colorAccum += dColor * edgeFade * 2.5;
      }
    }
    prevY = pos.y;

    // Photon ring glow near black hole
    float glowFactor = 0.015 / (r * r + 0.08);
    glowAccum += glowFactor;

    // Gravitational lensing: bend ray toward center
    // Pseudo-Schwarzschild geodesic approximation
    float force = uGravK / (r * r);
    vec3 forceDir = normalize(toCenter);
    dir = normalize(dir + forceDir * force * stepLen);

    // Step forward
    pos += dir * stepLen;
  }

  // Photon ring glow color (warm orange-white)
  glowColor = vec3(1.0, 0.7, 0.35) * glowAccum * 0.6;

  // Final color composition
  vec3 finalColor;

  if (absorbed) {
    // Ray absorbed by black hole - still show accumulated glow
    finalColor = colorAccum + glowColor;
    // Minimum visible brightness to prevent total black
    finalColor = max(finalColor, vec3(0.002));
  } else {
    // Ray escaped - add starfield
    vec3 stars = starfield(dir, iTime);
    finalColor = colorAccum + glowColor + stars;
  }

  // Exposure and tone mapping (Reinhard)
  finalColor *= uExposure;
  finalColor = finalColor / (1.0 + finalColor);

  // Slight vignette
  vec2 vigUv = vUv * 2.0 - 1.0;
  float vig = 1.0 - 0.3 * dot(vigUv, vigUv);
  finalColor *= vig;

  // Gamma correction
  finalColor = pow(finalColor, vec3(1.0 / 2.2));

  gl_FragColor = vec4(finalColor, 1.0);
}
`;

// ============================================================
// THREE.JS SCENE SETUP
// ============================================================

// Renderer
const renderer = new THREE.WebGLRenderer({ antialias: false });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

// Scene
const scene = new THREE.Scene();

// Camera (PerspectiveCamera used for both rendering AND OrbitControls)
const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
camera.position.set(0, 5, 20);  // Initial camera position
camera.lookAt(0, 0, 0);

// OrbitControls
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.08;
controls.minDistance = 1.5;    // Zoom limits
controls.maxDistance = 60.0;
controls.target.set(0, 0, 0);
controls.update();

// ============================================================
// SHADER MATERIAL + FULL-SCREEN QUAD
// ============================================================
const blackHoleMaterial = new THREE.ShaderMaterial({
  vertexShader: vertexShader,
  fragmentShader: fragmentShader,
  uniforms: {
    iTime:          { value: 0.0 },
    iResolution:    { value: new THREE.Vector2(Math.max(window.innerWidth, 1), Math.max(window.innerHeight, 1)) },
    iCameraPos:     { value: new THREE.Vector3() },
    iCameraDir:     { value: new THREE.Vector3() },
    iCameraUp:      { value: new THREE.Vector3(0, 1, 0) },
    iFov:           { value: 60.0 },
    uBhRadius:      { value: BH_RADIUS },
    uDiskInner:     { value: DISK_INNER },
    uDiskOuter:     { value: DISK_OUTER },
    uGravK:         { value: GRAV_CONSTANT },
    uExposure:      { value: EXPOSURE },
    uStarDensity:   { value: STAR_DENSITY },
    uDopplerStrength: { value: DOPPLER_STRENGTH }
  },
  depthWrite: false,
  depthTest: false
});

// Full-screen quad: PlaneGeometry(2,2) in NDC
const quadGeometry = new THREE.PlaneGeometry(2, 2);
const fullScreenMesh = new THREE.Mesh(quadGeometry, blackHoleMaterial);
fullScreenMesh.frustumCulled = false;  // REQUIRED: prevent frustum culling
scene.add(fullScreenMesh);             // Add to scene, NOT to camera

// ============================================================
// ANIMATION LOOP
// ============================================================
const clock = new THREE.Clock();
let shaderTime = 0.0;
const tempVec = new THREE.Vector3();
const resVec = new THREE.Vector2();

function animate() {
  requestAnimationFrame(animate);

  // 1. Update time based on animation toggle
  const animToggle = document.getElementById('anim-toggle');
  const delta = clock.getDelta();
  if (animToggle && animToggle.checked) {
    shaderTime += delta;
  }
  blackHoleMaterial.uniforms.iTime.value = shaderTime;

  // 2. Update resolution from actual drawing buffer (prevents 0,0 in headless)
  renderer.getDrawingBufferSize(resVec);
  blackHoleMaterial.uniforms.iResolution.value.set(
    Math.max(resVec.x, 1),
    Math.max(resVec.y, 1)
  );

  // 3. Update camera uniforms
  blackHoleMaterial.uniforms.iCameraPos.value.copy(camera.position);

  camera.getWorldDirection(tempVec);
  blackHoleMaterial.uniforms.iCameraDir.value.copy(tempVec);

  blackHoleMaterial.uniforms.iCameraUp.value.copy(camera.up);
  blackHoleMaterial.uniforms.iFov.value = camera.fov;

  // 4. Update controls and render
  controls.update();
  renderer.render(scene, camera);
}

// Handle window resize
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

// Start animation
animate();

</script>
</body>
</html>
